column.value:
{
  "pageDescription": "Sample Intake, Registration & Authentication",
  "dataPoints": {
    "sampleIdentity": {
      "uniqueSampleId": {"type": "system", "label": "Unique Sample ID (system-generated)"},
      "barcode": {"type": "system", "label": "Barcode / QR code"},
      "sampleCategory": {"type": "choice", "label": "Sample category", "options": ["Traditional medicine", "Modern medicine", "Hybrid research sample"], "required": true}
    },
    "sampleSourceOrigin": {
      "sourceType": {"type": "choice", "label": "Source type", "options": ["Plant material", "Other traditional medicine source"], "required": true},
      "originLocation": {"type": "text", "label": "Origin/location", "required": false},
      "collectionSite": {"type": "text", "label": "Collection site (GPS/region)", "required": false},
      "collectionDate": {"type": "dateTime", "label": "Collection date & time", "required": true},
      "collectedBy": {"type": "text", "label": "Collected by (name/role)", "required": true}
    },
    "taxonomyIdentification": {
      "localName": {"type": "text", "label": "Local/common name", "required": false},
      "scientificName": {"type": "text", "label": "Scientific name", "required": false},
      "species": {"type": "text", "label": "Species", "required": false},
      "plantPart": {"type": "choice", "label": "Plant part", "options": ["Root", "Leaf", "Stem", "Bark", "Flower", "Seed", "Whole plant"], "required": false},
      "sampleCondition": {"type": "choice", "label": "Sample condition", "options": ["Fresh", "Dried", "Preserved"], "required": true}
    },
    "authentication": {
      "authenticationMethod": {"type": "choice", "label": "Authentication method", "options": ["Botanical verification", "Expert identification", "Literature/database comparison", "Morphological analysis", "Chemical fingerprinting"], "required": true},
      "authenticationResult": {"type": "choice", "label": "Authentication result", "options": ["Confirmed", "Partially confirmed", "Not confirmed", "Pending review"], "required": true},
      "verifiedBy": {"type": "text", "label": "Verified by", "required": false},
      "verificationDate": {"type": "date", "label": "Verification date", "required": false},
      "authenticationNotes": {"type": "text", "label": "Authentication notes", "required": false}
    },
    "intendedUse": {
      "purpose": {"type": "choice", "label": "Intended use", "options": ["Research only", "Analytical profiling", "Product development", "Reference/herbarium specimen"], "required": true}
    }
  },
  "systemActions": ["Sample record created", "Label generated and affixed", "Authentication recorded", "Confirmed samples advance to Storage"],
  "nextPage": "Sample Storage & Herbarium Placement"
}

{
  "pageDescription": "Sample Storage & Herbarium Placement",
  "dataPoints": {
    "storageOptions": {
      "storageType": {"type": "choice", "label": "Storage type", "options": ["Refrigerated", "Dried (ambient)", "Preserved (chemical/ethanol)", "Frozen"], "required": true}
    },
    "storageLocation": {
      "room": {"type": "text", "label": "Room", "required": false},
      "storageDevice": {"type": "text", "label": "Storage device", "required": false},
      "rack": {"type": "text", "label": "Rack", "required": false},
      "box": {"type": "text", "label": "Box", "required": false},
      "position": {"type": "text", "label": "Position", "required": false}
    },
    "herbariumPlacement": {
      "herbariumId": {"type": "text", "label": "Herbarium ID", "required": false},
      "mounted": {"type": "choice", "label": "Mounted", "options": ["Yes", "No"], "required": false},
      "labelConfirmed": {"type": "choice", "label": "Label confirmed", "options": ["Yes", "No"], "required": false},
      "catalogNumber": {"type": "text", "label": "Catalog number", "required": false},
      "dateCataloged": {"type": "date", "label": "Date cataloged", "required": false}
    }
  },
  "systemActions": ["Location logged", "Sample status: In Storage / Herbarium Reference"],
  "nextPage": "Sample Preparation for Analysis"
}

{
  "pageDescription": "Sample Preparation for Analysis",
  "dataPoints": {
    "physicalProcessing": {
      "processingType": {"type": "choice", "label": "Processing type", "options": ["Grinding", "Chopping", "Drying", "Powdering"], "required": true},
      "processingMethod": {"type": "choice", "label": "Processing method", "options": ["Fresh processing", "Dried processing"], "required": true},
      "processingDate": {"type": "date", "label": "Processing date", "required": true},
      "processedBy": {"type": "text", "label": "Processed by", "required": true}
    }
  },
  "systemActions": ["Processing step logged", "Derived material linked to parent sample", "Status: Prepared for Extraction"],
  "nextPage": "Extraction, Filtration & Concentration"
}

{
  "pageDescription": "Extraction, Filtration & Concentration",
  "dataPoints": {
    "extraction": {
      "solventUsed": {"type": "choice", "label": "Solvent used", "options": ["Ethanol", "Methanol", "Water", "Hexane", "Chloroform", "Acetone", "Other"], "required": true},
      "extractionTechnique": {"type": "choice", "label": "Extraction technique", "options": ["Maceration", "Soxhlet", "Ultrasonic", "Distillation", "Cold press", "Supercritical CO2", "Other"], "required": true},
      "extractionDate": {"type": "date", "label": "Extraction date", "required": true},
      "operator": {"type": "text", "label": "Operator", "required": true}
    },
    "filtration": {
      "filtrationMethod": {"type": "text", "label": "Filtration method", "required": false},
      "debrisRemoved": {"type": "choice", "label": "Debris removed", "options": ["Yes", "No"], "required": false}
    },
    "concentration": {
      "concentrationMethod": {"type": "choice", "label": "Concentration method", "options": ["Rotary evaporation", "Freeze drying", "Spray drying", "Vacuum distillation"], "required": false},
      "finalVolume": {"type": "text", "label": "Final volume", "required": false},
      "concentrationDate": {"type": "date", "label": "Concentration date", "required": false}
    }
  },
  "systemActions": ["Extract record created (child of sample)", "Parent-child traceability enforced", "Aliquoting supported", "Status: Extract Ready"],
  "nextPage": "Analytical Pathway / Product Development & Testing"
}

{
  "pageDescription": "Analytical Pathway (Optional)",
  "dataPoints": {
    "fractionation": {
      "fractionationMethod": {"type": "text", "label": "Fractionation method", "required": false},
      "numberOfFractions": {"type": "text", "label": "Number of fractions", "required": false},
      "fractionIds": {"type": "text", "label": "Fraction IDs", "required": false}
    },
    "identificationIsolation": {
      "activeConstituentsIdentified": {"type": "choice", "label": "Active constituents identified", "options": ["Yes", "No"], "required": false},
      "linkedCompoundDatabase": {"type": "text", "label": "Linked compound database entry", "required": false}
    },
    "purification": {
      "purificationMethod": {"type": "text", "label": "Purification method", "required": false},
      "purityLevel": {"type": "text", "label": "Purity level (%)", "required": false}
    },
    "characterization": {
      "structuralAnalysis": {"type": "multiChoice", "label": "Structural analysis", "options": ["NMR", "MS", "IR", "UV-Vis", "HPLC", "GC-MS"], "required": false},
      "spectralFilesUploaded": {"type": "choice", "label": "Spectral files uploaded", "options": ["Yes", "No"], "required": false}
    }
  },
  "systemActions": ["Analytical data linked to extract", "Skip to Testing available", "Status: Characterized"],
  "nextPage": "Product Development & Testing"
}

{
  "pageDescription": "Product Development & Testing",
  "dataPoints": {
    "phytochemicalScreening": {
      "testsPerformed": {"type": "multiChoice", "label": "Phytochemical tests", "options": ["Alkaloids", "Flavonoids", "Tannins", "Saponins", "Glycosides", "Terpenoids", "Steroids", "Phenols"], "required": false},
      "resultsRecorded": {"type": "text", "label": "Results recorded", "required": false}
    },
    "safetyToxicityStudy": {
      "studyType": {"type": "choice", "label": "Study type", "options": ["In vitro", "In vivo - Acute", "In vivo - Subacute", "In vivo - Chronic", "Genotoxicity", "Cytotoxicity"], "required": false},
      "toxicityModel": {"type": "choice", "label": "Model/System", "options": ["Cell line", "Rodent (mouse)", "Rodent (rat)", "Zebrafish", "Brine shrimp", "Other"], "required": false},
      "toxicityOutcome": {"type": "choice", "label": "Toxicity outcome", "options": ["Safe", "Low toxicity", "Moderate toxicity", "High toxicity", "Inconclusive"], "required": false},
      "externalStudyReference": {"type": "text", "label": "External study reference", "required": false}
    },
    "efficacyTesting": {
      "biologicalAssayType": {"type": "choice", "label": "Biological assay type", "options": ["Antimicrobial", "Antioxidant", "Anti-inflammatory", "Antidiabetic", "Anticancer", "Analgesic", "Hepatoprotective", "Immunomodulatory", "Wound healing", "Other"], "required": false},
      "efficacyOutcome": {"type": "choice", "label": "Efficacy outcome", "options": ["Highly effective", "Moderately effective", "Weakly effective", "Not effective", "Inconclusive"], "required": false},
      "protocolReference": {"type": "text", "label": "Protocol reference", "required": false}
    }
  },
  "systemActions": ["Testing outcomes attached to sample lineage", "Status: Approved for Formulation / Rejected / Further Testing Required"],
  "nextPage": "Formulation of Medical Product"
}

{
  "pageDescription": "Formulation of Medical Product",
  "dataPoints": {
    "formulationDetails": {
      "productType": {"type": "choice", "label": "Product type", "options": ["Capsule", "Tablet", "Tincture", "Ointment", "Tea", "Powder", "Syrup", "Oil", "Poultice", "Suppository", "Lotion", "Other"], "required": true},
      "productName": {"type": "text", "label": "Product name", "required": false},
      "ingredients": {"type": "text", "label": "Ingredients (linked to extracts)", "required": true},
      "batchId": {"type": "text", "label": "Batch ID", "required": true},
      "formulationDate": {"type": "date", "label": "Formulation date", "required": true},
      "preparedBy": {"type": "text", "label": "Prepared by", "required": true},
      "dosageForm": {"type": "choice", "label": "Dosage form", "options": ["Oral", "Topical", "Sublingual", "Inhalation", "Rectal", "Nasal", "Other"], "required": false},
      "strength": {"type": "text", "label": "Strength", "required": false},
      "quantity": {"type": "text", "label": "Quantity produced", "required": false},
      "shelfLife": {"type": "text", "label": "Shelf life", "required": false},
      "storageInstructions": {"type": "text", "label": "Storage instructions", "required": false}
    }
  },
  "systemActions": ["Product batch created", "Linked to original sample", "Status: Product Formulated"],
  "nextPage": "Storage, Reporting & Archival"
}

{
  "pageDescription": "Storage, Reporting & Archival",
  "dataPoints": {
    "storage": {
      "finishedProductStorageLocation": {"type": "text", "label": "Finished product storage location", "required": false},
      "storageCondition": {"type": "text", "label": "Storage condition", "required": false}
    },
    "reporting": {
      "sampleHistoryReport": {"type": "choice", "label": "Sample history report generated", "options": ["Yes", "No"], "required": false},
      "processingTestingSummary": {"type": "choice", "label": "Processing & testing summary generated", "options": ["Yes", "No"], "required": false},
      "productLineageReport": {"type": "choice", "label": "Product lineage report generated", "options": ["Yes", "No"], "required": false}
    },
    "archival": {
      "rawDataArchived": {"type": "choice", "label": "Raw data archived", "options": ["Yes", "No"], "required": false},
      "spectralDataArchived": {"type": "choice", "label": "Spectral data archived", "options": ["Yes", "No"], "required": false},
      "metadataLocked": {"type": "choice", "label": "Metadata locked", "options": ["Yes", "No"], "required": false}
    }
  },
  "systemActions": ["Sample lifecycle marked Completed", "Records preserved for long-term reference"],
  "nextPage": null
}
